import { jest } from '@jest/globals';

/**
 * Unit tests for the main CodestralApp orchestrator
 * Note: We can't directly import the CodestralApp class since it's in the bin file
 * and runs immediately. These tests verify the components work together.
 */
describe('CodestralApp Integration', () => {
  describe('Component Initialization', () => {
    it('should have all required components available', async () => {
      // Import all components to verify they exist and can be instantiated
      const ConfigManager = (await import('../src/config/ConfigManager.js')).default;
      const MistralClient = (await import('../src/ai/MistralClient.js')).default;
      const TerminalInterface = (await import('../src/cli/TerminalInterface.js')).default;
      const InputParser = (await import('../src/parser/InputParser.js')).default;
      const MentionResolver = (await import('../src/mentions/MentionResolver.js')).default;
      const ContextManager = (await import('../src/context/ContextManager.js')).default;
      const FileSystemManager = (await import('../src/filesystem/FileSystemManager.js')).default;
      const ErrorHandler = (await import('../src/utils/ErrorHandler.js')).default;

      // Verify all components can be instantiated
      expect(ConfigManager).toBeDefined();
      expect(MistralClient).toBeDefined();
      expect(TerminalInterface).toBeDefined();
      expect(InputParser).toBeDefined();
      expect(MentionResolver).toBeDefined();
      expect(ContextManager).toBeDefined();
      expect(FileSystemManager).toBeDefined();
      expect(ErrorHandler).toBeDefined();
    });

    it('should instantiate ConfigManager', async () => {
      const ConfigManager = (await import('../src/config/ConfigManager.js')).default;
      const configManager = new ConfigManager();
      
      expect(configManager).toBeDefined();
      expect(typeof configManager.load).toBe('function');
      expect(typeof configManager.save).toBe('function');
    });

    it('should instantiate TerminalInterface', async () => {
      const TerminalInterface = (await import('../src/cli/TerminalInterface.js')).default;
      const terminal = new TerminalInterface({
        syntaxHighlight: true,
        theme: 'default'
      });
      
      expect(terminal).toBeDefined();
      expect(typeof terminal.start).toBe('function');
      expect(typeof terminal.prompt).toBe('function');
      expect(typeof terminal.display).toBe('function');
    });

    it('should instantiate InputParser', async () => {
      const InputParser = (await import('../src/parser/InputParser.js')).default;
      const parser = new InputParser();
      
      expect(parser).toBeDefined();
      expect(typeof parser.parse).toBe('function');
      expect(typeof parser.extractMentions).toBe('function');
    });

    it('should instantiate FileSystemManager', async () => {
      const FileSystemManager = (await import('../src/filesystem/FileSystemManager.js')).default;
      const fsManager = new FileSystemManager(process.cwd());
      
      expect(fsManager).toBeDefined();
      expect(typeof fsManager.readFile).toBe('function');
      expect(typeof fsManager.writeFile).toBe('function');
    });

    it('should instantiate MentionResolver with FileSystemManager', async () => {
      const FileSystemManager = (await import('../src/filesystem/FileSystemManager.js')).default;
      const MentionResolver = (await import('../src/mentions/MentionResolver.js')).default;
      
      const fsManager = new FileSystemManager(process.cwd());
      const mentionResolver = new MentionResolver(fsManager);
      
      expect(mentionResolver).toBeDefined();
      expect(typeof mentionResolver.resolve).toBe('function');
      expect(typeof mentionResolver.readMentionedFiles).toBe('function');
    });

    it('should instantiate ContextManager', async () => {
      const ContextManager = (await import('../src/context/ContextManager.js')).default;
      const contextManager = new ContextManager(8000);
      
      expect(contextManager).toBeDefined();
      expect(typeof contextManager.addMessage).toBe('function');
      expect(typeof contextManager.getMessages).toBe('function');
      expect(typeof contextManager.truncate).toBe('function');
    });

    it('should instantiate MistralClient', async () => {
      const MistralClient = (await import('../src/ai/MistralClient.js')).default;
      const client = new MistralClient('test-api-key', {
        model: 'mistral-large-latest',
        maxTokens: 4096,
        temperature: 0.7
      });
      
      expect(client).toBeDefined();
      expect(typeof client.sendMessage).toBe('function');
      expect(typeof client.streamResponse).toBe('function');
    });

    it('should instantiate ErrorHandler', async () => {
      const ErrorHandler = (await import('../src/utils/ErrorHandler.js')).default;
      const logger = (await import('../src/utils/logger.js')).default;
      const errorHandler = new ErrorHandler(logger);
      
      expect(errorHandler).toBeDefined();
      expect(typeof errorHandler.handle).toBe('function');
    });
  });

  describe('Component Wiring', () => {
    it('should wire InputParser with MentionResolver', async () => {
      const InputParser = (await import('../src/parser/InputParser.js')).default;
      const MentionResolver = (await import('../src/mentions/MentionResolver.js')).default;
      const FileSystemManager = (await import('../src/filesystem/FileSystemManager.js')).default;

      const parser = new InputParser();
      const fsManager = new FileSystemManager(process.cwd());
      const mentionResolver = new MentionResolver(fsManager);

      // Parse input with mentions
      const input = 'Check @README.md';
      const parsed = parser.parse(input);

      expect(parsed.mentions).toEqual(['README.md']);

      // Mentions can be resolved
      const resolved = await mentionResolver.resolve(parsed.mentions);
      expect(resolved).toBeDefined();
      expect(Array.isArray(resolved)).toBe(true);
    });

    it('should wire MentionResolver with ContextManager', async () => {
      const MentionResolver = (await import('../src/mentions/MentionResolver.js')).default;
      const ContextManager = (await import('../src/context/ContextManager.js')).default;
      const FileSystemManager = (await import('../src/filesystem/FileSystemManager.js')).default;

      const fsManager = new FileSystemManager(process.cwd());
      const mentionResolver = new MentionResolver(fsManager);
      const contextManager = new ContextManager(8000);

      // Simulate reading a file and adding to context
      const filePath = 'test.js';
      const content = 'console.log("test");';

      contextManager.addFileContext(filePath, content);

      const fileContext = contextManager.getFileContext(filePath);
      expect(fileContext).toBeDefined();
      expect(fileContext.path).toBe(filePath);
      expect(fileContext.content).toBe(content);
    });

    it('should wire ContextManager with MistralClient', async () => {
      const ContextManager = (await import('../src/context/ContextManager.js')).default;
      const MistralClient = (await import('../src/ai/MistralClient.js')).default;

      const contextManager = new ContextManager(8000);
      const mistralClient = new MistralClient('test-api-key');

      // Add messages to context
      contextManager.addMessage('user', 'Hello');
      contextManager.addMessage('assistant', 'Hi there!');

      // Get messages in format for AI
      const messages = contextManager.getMessages().map(msg => ({
        role: msg.role,
        content: msg.content
      }));

      expect(messages).toHaveLength(2);
      expect(messages[0].role).toBe('user');
      expect(messages[1].role).toBe('assistant');

      // Verify format is compatible with MistralClient
      // (We don't actually call the API in tests)
      expect(messages.every(m => m.role && m.content)).toBe(true);
    });
  });

  describe('Command Handling', () => {
    it('should parse help command', async () => {
      const InputParser = (await import('../src/parser/InputParser.js')).default;
      const parser = new InputParser();

      const parsed = parser.parse('/help');

      expect(parsed.isCommand).toBe(true);
      expect(parsed.command.name).toBe('help');
      expect(parsed.command.isSupported).toBe(true);
    });

    it('should parse clear command', async () => {
      const InputParser = (await import('../src/parser/InputParser.js')).default;
      const parser = new InputParser();

      const parsed = parser.parse('/clear');

      expect(parsed.isCommand).toBe(true);
      expect(parsed.command.name).toBe('clear');
      expect(parsed.command.isSupported).toBe(true);
    });

    it('should parse set command with arguments', async () => {
      const InputParser = (await import('../src/parser/InputParser.js')).default;
      const parser = new InputParser();

      const parsed = parser.parse('/set mistral.temperature 0.8');

      expect(parsed.isCommand).toBe(true);
      expect(parsed.command.name).toBe('set');
      expect(parsed.command.args).toBe('mistral.temperature 0.8');
      expect(parsed.command.isSupported).toBe(true);
    });
  });

  describe('Error Handling', () => {
    it('should handle errors with ErrorHandler', async () => {
      const ErrorHandler = (await import('../src/utils/ErrorHandler.js')).default;
      const logger = (await import('../src/utils/logger.js')).default;
      const errorHandler = new ErrorHandler(logger);

      const error = new Error('Test error');
      const result = errorHandler.handle(error, { context: 'test' });

      expect(result).toBeDefined();
      expect(result.message).toBeDefined();
      expect(typeof result.message).toBe('string');
      expect(result.type).toBeDefined();
    });
  });
});
